#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e6+10;
stack<int>s;
int h[MAXN],v[MAXN],ans[MAXN];
int main()
{
	int n;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>h[i]>>v[i];
		while(s.size()&&h[s.top()]<h[i])
		{
//			cout<<s.size()<<" "<<h[s.top()]<<" "<<h[i]<<endl;
			int u=s.top();
			s.pop();
			ans[i]+=v[u];
		}
		if(s.size())
			ans[s.top()]+=v[i];
		s.push(i);
	}
	int maxi=0;
	for(int i=1;i<=n;i++)maxi=max(maxi,ans[i]);
	cout<<maxi;
}
